import { Paper, Typography } from "@mui/material";
import React from "react";
import SimpleHeader from "../../components/SimpleHeader";
import ContentCopyIcon from "@mui/icons-material/ContentCopy";
import IconButton from "@mui/material/IconButton";
import QrCodeIcon from "@mui/icons-material/QrCode";
import { QRCodeSVG } from "qrcode.react";
import Dialog from "@mui/material/Dialog";
import DialogContent from "@mui/material/DialogContent";
import DialogContentText from "@mui/material/DialogContentText";
import DialogTitle from "@mui/material/DialogTitle";
import Slide from "@mui/material/Slide";
import { useNavigate } from "react-router-dom";
import { TransitionProps } from "@mui/material/transitions";

const Transition = React.forwardRef(function Transition(
  props: TransitionProps & {
    children: React.ReactElement<any, any>,
  },
  ref: React.Ref<unknown>
) {
  return <Slide direction="up" ref={ref} {...props} />;
});

const Donate = () => {
  let navigate = useNavigate();
  const [open, setOpen] = React.useState(false);
  const handleClickOpen = () => {
    setOpen(true);
  };

  const handleClose = () => {
    setOpen(false);
  };
  const routeChange = () => {
    let path = "/";
    navigate(path);
  };

  return (
    <React.Fragment>
      <SimpleHeader headerText="Donate" routeChange={routeChange} />
      <Paper elevation={3} style={{ borderRadius: 0, padding: 10, marginTop: 10 }}>
        <Typography variant="subtitle1">Bitcoin Address</Typography>
        <Typography variant="subtitle2"> bc1qgupz6umcs2lvfnenv5l9fatxuhpqex4w7793s8</Typography>
        <div style={{ display: "flex", justifyContent: "flex-end" }}>
          <IconButton aria-label="settings" style={{ backgroundColor: "#EBEDF0", marginRight: 5 }}>
            <ContentCopyIcon />
          </IconButton>
          <IconButton
            aria-label="settings"
            style={{ backgroundColor: "#EBEDF0" }}
            onClick={handleClickOpen}
          >
            <QrCodeIcon />
          </IconButton>
        </div>

        <div>
          <Dialog
            open={open}
            TransitionComponent={Transition}
            keepMounted
            onClose={handleClose}
            aria-describedby="alert-dialog-slide-description"
          >
            <DialogTitle> bc1qgupz6umcs2lvfnenv5l9fatxuhpqex4w7793s8</DialogTitle>
            <DialogContent>
              <DialogContentText
                id="alert-dialog-slide-description"
                style={{ textAlign: "center" }}
              >
                <QRCodeSVG value="https://reactjs.org/" />,
              </DialogContentText>
            </DialogContent>
          </Dialog>
        </div>
      </Paper>
    </React.Fragment>
  );
};
export default Donate;
